INSERT INTO public.question_bank (question, option_a, option_b, option_c, option_d, correct_answer, explanation, topic, department, difficulty, skill_tag, trap_type, time_limit, score, quality_score, source_type) VALUES
('Khách nói giá bên mình cao hơn shop khác 300.000đ. Nên trả lời thế nào?','Nêu giá trị và hậu mãi rõ ràng.','Nói shop kia có thể bán hàng kém.','Bảo khách tự so sánh thêm rồi quyết.','Giảm giá ngay để giữ khách.','A','A giữ uy tín, không công kích đối thủ và nêu đúng giá trị.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Xử lý phản đối','So sánh giá',20,10,100,'csv_import'),
('Khách chỉ hỏi giá rồi im lặng. Việc tiếp theo nên làm gì?','Gửi thêm bảng giá thật chi tiết ngay.','Hỏi nhu cầu dùng và độ tuổi bé.','Nhắn liên tục để khách nhớ shop.','Chờ khách cần thì quay lại.','B','B mở lại hội thoại bằng nhu cầu thật thay vì chỉ bám giá.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Khai thác nhu cầu','Im lặng sau báo giá',20,10,100,'csv_import'),
('Phụ huynh bảo bé mới tập nhưng muốn mua mẫu rẻ nhất. Nên ưu tiên gì?','Chọn mẫu bất kỳ đang giảm sâu ngay ngay ngay.','Giải thích an toàn trước rồi gợi mẫu phù hợp.','Báo mẫu rẻ nhất để chốt nhanh.','Khuyên khách đợi khi bé lớn hơn.','B','B cân bằng ngân sách và an toàn, không bán bằng mọi giá.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Tư vấn an toàn','Giá rẻ hơn phù hợp',20,10,100,'csv_import'),
('Khách hỏi còn size nhưng kho chưa cập nhật chắc chắn. Nên làm gì?','Hứa còn hàng để giữ khách ngay.','Báo hết hàng cho an toàn.','Kiểm tra kho rồi phản hồi nhanh.','Chuyển khách sang mẫu đắt hơn.','C','C giảm rủi ro hứa sai và vẫn giữ tốc độ tư vấn.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Kiểm tra tồn kho','Hứa khi chưa xác minh',20,10,100,'csv_import'),
('Khách muốn đổi size sau khi đã dùng thử ngoài sân. Nên xử lý sao?','Từ chối ngay vì đã sử dụng ngay.','Đổi luôn để khách vui hơn.','Kiểm tra tình trạng rồi áp chính sách.','Bảo khách tự bán lại sản phẩm.','C','C đúng vì cần kiểm tra thực tế trước khi quyết định.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Đổi trả','Cứng nhắc hoặc dễ dãi',20,10,100,'csv_import'),
('Khách hỏi mẫu nào tốt nhất cho bé 6 tuổi mới tập. Câu hỏi đầu tiên nên là gì?','Bé thích màu nào nhất ạ?','Bé cao nặng và đi size bao nhiêu?','Anh chị muốn mua tầm giá nào? ngay.','Mẫu đắt nhất bên em rất tốt.','B','B giúp xác định size và độ phù hợp trước khi tư vấn mẫu.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Tư vấn size','Hỏi sai ưu tiên',20,10,100,'csv_import'),
('Khách so sánh giá Shopee rẻ hơn cửa hàng. Nên xử lý thế nào?','Nói Shopee nhiều hàng không chuẩn.','Giải thích chương trình sàn và dịch vụ cửa hàng.','Bảo khách mua Shopee cho rẻ.','Giảm giá bằng Shopee ngay lập tức ngay ngay ngay.','B','B giải thích khác biệt kênh bán mà không làm mất uy tín.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Đa kênh','Xung đột giá',20,10,100,'csv_import'),
('Khách đòi giảm thêm vì mua hai đôi. Cách xử lý tốt nhất?','Từ chối thẳng vì giá niêm yết ngay ngay.','Kiểm tra ưu đãi hợp lệ rồi đề xuất.','Giảm tùy ý để chốt đơn.','Nói mua nhiều chưa chắc được giảm.','B','B giữ chính sách giá và vẫn tạo cảm giác được hỗ trợ.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Chốt đơn','Giảm giá cảm tính',20,10,100,'csv_import'),
('Khách hỏi quá nhiều nhưng chưa mua. Nhân viên nên làm gì?','Trả lời ngắn cho đỡ mất thời gian ngay.','Tóm tắt nhu cầu và gợi 2 lựa chọn.','Gửi toàn bộ catalogue cho khách tự xem.','Nói khách ra cửa hàng thử trực tiếp.','B','B giúp khách ra quyết định, tránh làm khách ngợp thông tin.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Tư vấn lựa chọn','Quá tải thông tin',20,10,100,'csv_import'),
('Khách bảo bé sợ ngã nên chưa dám mua patin. Nên nhấn mạnh gì?','Mua giày xịn sẽ không ngã.','Bảo hộ và tập từng bước an toàn.','Bé nào mới tập cũng ngã thôi ngay.','Đợi bé lớn hơn rồi mua.','B','B xử lý đúng nỗi sợ bằng giải pháp thực tế và an toàn.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Trung bình','Xử lý nỗi sợ','Cam kết quá đà',20,10,100,'csv_import'),
('Khi tư vấn giày patin, khách chê đắt. Cách xử lý nào đúng nhất?','Hỏi rõ nhu cầu rồi mới đề xuất.','Trả lời nhanh theo mẫu có sẵn ngay.','Đẩy khách sang mẫu đang tồn kho.','Hứa chắc chắn dù chưa kiểm tra.','A','Đúng nhất là khai thác nhu cầu trước, tránh tư vấn theo cảm tính.','Bẫy Não Bán Hàng','Cửa hàng / TMĐT','Dễ','Tư vấn khách','Đáp án nghe hợp lý nhưng thiếu gốc',20,10,100,'csv_import'),
